appsmith.onReady(() => {
  renderExecutiveSummary();
});
appsmith.onModelChange(() => {
  renderExecutiveSummary();
});
function renderExecutiveSummary() {
  const data = appsmith.model;
  const current = data.current_scan || {};
  const telemetry = data.telemetry || {};
  const baseline = data.baseline || {};

  // 1. Extract Current Metrics
  const violationRate = current.data_policy_violation_rate?.rate || 0;
  const totalViolations = current.data_policy_violation_rate?.violations || 0;
  const piiUsedCount = current.count_pii_used?.total_pii || 0;
  const piiTypes = current.count_pii_used?.pii_types || [];
  const egressMb = telemetry.proprietary_data_egress_mb || 0;

  // 2. Determine Overall Risk Tier
  const tierEl = document.getElementById('risk-tier');
  const tierContextEl = document.getElementById('risk-tier-context');
  if (violationRate === 1.0 || piiUsedCount > 0 || egressMb > 0) {
    tierEl.textContent = "CRITICAL";
    tierEl.className = "value text-critical";
    tierContextEl.textContent = "100% Policy Violation Rate";
  } else if (totalViolations > 0) {
    tierEl.textContent = "HIGH";
    tierEl.className = "value text-warning";
    tierContextEl.textContent = "Policy Violations Detected";
  } else {
    tierEl.textContent = "ACCEPTABLE";
    tierEl.className = "value text-safe";
    tierContextEl.textContent = "Within Governance Baselines";
  }

  // 3. Populate KPIs
  document.getElementById('data-egress').textContent = `${egressMb} MB`;
  document.getElementById('pii-count').textContent = piiUsedCount;

  // 4. Calculate Risk Delta
  const deltaEl = document.getElementById('risk-delta');
  const deltaContextEl = document.getElementById('delta-context');
  const violationDiff = totalViolations - (baseline.previous_violations || 0);
  if (violationDiff > 0) {
    deltaEl.textContent = `+${violationDiff} Violations`;
    deltaEl.className = "value text-critical";
    deltaContextEl.textContent = "Degradation since last scan";
  } else if (violationDiff < 0) {
    deltaEl.textContent = `${violationDiff} Violations`;
    deltaEl.className = "value text-safe";
    deltaContextEl.textContent = "Improvement since last scan";
  } else {
    deltaEl.textContent = "No Change";
    deltaEl.className = "value";
    deltaContextEl.textContent = "Stable since last scan";
  }

  // 5. Generate Top 3 Priority Signals
  const signals = [];
  if (violationRate === 1.0) {
    signals.push({
      text: `<strong>AI Data Eligibility Violation:</strong> 100% of variables used in the model (${totalViolations} total) are not supported by the current data policy.`,
      severity: 3
    });
  }
  if (piiUsedCount > 0) {
    signals.push({
      text: `<strong>Sensitive Input Signal:</strong> Detected ingestion of ${piiUsedCount} restricted PII fields: ${piiTypes.join(', ')}.`,
      severity: 3
    });
  }
  if (egressMb > 0) {
    signals.push({
      text: `<strong>Inference Exposure Signal:</strong> Active egress of ${egressMb} MB detected, indicating potential output leakage or persistence exposure.`,
      severity: 2
    });
  }

  // Sort by severity and grab top 3
  signals.sort((a, b) => b.severity - a.severity);
  const top3 = signals.slice(0, 3);
  const listEl = document.getElementById('top-signals-list');
  listEl.innerHTML = "";
  if (top3.length === 0) {
    listEl.innerHTML = "<li>No critical governance gaps or exposure signals detected.</li>";
  } else {
    top3.forEach(signal => {
      const li = document.createElement('li');
      li.innerHTML = signal.text;
      listEl.appendChild(li);
    });
  }
}

